// Generated by Spec-to-RTL pipeline: grammar -> IR -> RTL
// normalized from unstructured text
// Repair demo setup: injected an output bug that forces count to zero

module text_counter (
    input clk,
    input rst_n,
    input enable,
    output reg [7:0] count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count <= 8'd0;
        end else begin
            count <= 8'd0;
            if (enable) begin
                count <= 8'd0;
            end
        end
    end

endmodule
